module RefModule(
	input clk,
	input rst_n,
	input [7:0] duty_cycle,
	output reg pwm_out
);

	reg [7:0] unused_counter;

	always @(posedge clk or negedge rst_n) begin
		if (!rst_n)
			unused_counter <= 8'b0;
		else
			unused_counter <= unused_counter + 1;
	end

	always @(posedge clk or negedge rst_n) begin
		if (!rst_n)
			pwm_out <= 1'b0;
		else
			pwm_out <= (unused_counter < duty_cycle) ? 1'b1 : 1'b0;
	end

endmodule
